### Add Two Inline Embeds with Different Init Configs and Namespaces (JavaScript)

Source: https://github.com/calcom/cal.com/blob/main/packages/embeds/embed-core/index.html

This function initializes Cal.com twice with different configurations and namespaces. It then embeds inline elements, each associated with its respective namespace, demonstrating how to manage multiple independent embed instances.

```javascript
function addTwoInlineEmbedWithTwoDifferentNamespacesWithDifferentInitConfig() {
  Cal("init", "namespace-init-test-1", {
    debug: true,
    calOrigin: window.calOrigin,
  });
  Cal("init", "namespace-init-test-2", {
    debug: true,
    calOrigin: "http://127.0.0.1:3000",
  });
  Cal.ns['namespace-init-test-2']("inline", {
    elementOrSelector: '#two-different-namespace-with-different-init-config-content-2',
    calLink: "pro",
    config: {
      "flag.coep": "true"
    }
  });
  Cal.ns['namespace-init-test-1']("inline", {
    elementOrSelector: '#two-different-namespace-with-different-init-config-content-1',
    calLink: "pro",
    config: {
      "flag.coep": "true"
    }
  });
}
```

