### Double Install Snippet with Inline Embed - Non Default Namespace (JavaScript)

Source: https://github.com/calcom/cal.com/blob/main/packages/embeds/embed-core/index.html

This function demonstrates double installation of the Cal.com snippet, first with a specific namespace ('doubleInstall') and then using the default initialization. It embeds an inline element using the non-default namespace.

```javascript
function doubleInstallSnippetWithInlineEmbedWithNonDefaultNamespace(selector) {
  Cal("init", "doubleInstall", {
    debug: true,
    calOrigin: window.calOrigin,
  });
  Cal.ns.doubleInstall("inline", {
    elementOrSelector: selector,
    calLink: "pro?case=doubleInstallSnippetWithInlineEmbedWithNonDefaultNamespace",
    config: {
      "flag.coep": "true"
    }
  });
  embedSnippet();
  Cal("init", "doubleInstall", {
    debug: true,
    calOrigin: window.calOrigin,
  });
  Cal.ns.doubleInstall("inline", {
    elementOrSelector: selector,
    calLink: "pro",
    config: {
      "flag.coep": "true"
    }
  });
}
```

